<!--
  Connection Indicator Component
  Compact connection status indicator for main UI
-->

<script lang=\"ts\">
\timport { 
\t\tconnectionStatusStore,
\t\tisWebSocketConnected,
\t\tisCameraConnected,
\t\tisFullyConnected,
\t\tconnectionQuality,
\t\thasConnectionErrors,
\t\ttype ConnectionStatus
\t} from '$lib/utils/connectionDiagnostics';
\timport { triggerHaptic } from '$lib/utils/touchInteractions';
\timport { createEventDispatcher } from 'svelte';
\t
\t// Props\n\texport let showLabel = true;\n\texport let showQuality = true;\n\texport let clickable = true;\n\texport let size: 'sm' | 'md' | 'lg' = 'md';\n\texport let className = '';\n\t\n\t// Event dispatcher\n\tconst dispatch = createEventDispatcher<{\n\t\tclick: { status: ConnectionStatus };\n\t}>>();\n\t\n\t// Component state\n\tlet status: ConnectionStatus;\n\t\n\t// Reactive subscriptions\n\t$: wsConnected = $isWebSocketConnected;\n\t$: cameraConnected = $isCameraConnected;\n\t$: fullyConnected = $isFullyConnected;\n\t$: quality = $connectionQuality;\n\t$: hasErrors = $hasConnectionErrors;\n\t\n\t// Subscribe to status updates\n\tconst unsubscribe = connectionStatusStore.subscribe(s => status = s);\n\t\n\tfunction getOverallStatus(): 'connected' | 'partial' | 'disconnected' | 'error' {\n\t\tif (hasErrors) return 'error';\n\t\tif (fullyConnected) return 'connected';\n\t\tif (wsConnected || cameraConnected) return 'partial';\n\t\treturn 'disconnected';\n\t}\n\t\n\tfunction getStatusIcon(): string {\n\t\tconst overallStatus = getOverallStatus();\n\t\tswitch (overallStatus) {\n\t\t\tcase 'connected':\n\t\t\t\treturn '🟢';\n\t\t\tcase 'partial':\n\t\t\t\treturn '🟡';\n\t\t\tcase 'disconnected':\n\t\t\t\treturn '🔴';\n\t\t\tcase 'error':\n\t\t\t\treturn '❌';\n\t\t\tdefault:\n\t\t\t\treturn '⚪';\n\t\t}\n\t}\n\t\n\tfunction getStatusText(): string {\n\t\tconst overallStatus = getOverallStatus();\n\t\tswitch (overallStatus) {\n\t\t\tcase 'connected':\n\t\t\t\treturn 'Connected';\n\t\t\tcase 'partial':\n\t\t\t\treturn wsConnected ? 'Server Only' : 'Camera Only';\n\t\t\tcase 'disconnected':\n\t\t\t\treturn 'Disconnected';\n\t\t\tcase 'error':\n\t\t\t\treturn 'Error';\n\t\t\tdefault:\n\t\t\t\treturn 'Unknown';\n\t\t}\n\t}\n\t\n\tfunction getStatusColor(): string {\n\t\tconst overallStatus = getOverallStatus();\n\t\tswitch (overallStatus) {\n\t\t\tcase 'connected':\n\t\t\t\treturn 'text-green-400';\n\t\t\tcase 'partial':\n\t\t\t\treturn 'text-yellow-400';\n\t\t\tcase 'disconnected':\n\t\t\t\treturn 'text-gray-400';\n\t\t\tcase 'error':\n\t\t\t\treturn 'text-red-400';\n\t\t\tdefault:\n\t\t\t\treturn 'text-gray-400';\n\t\t}\n\t}\n\t\n\tfunction getQualityIcon(): string {\n\t\tswitch (quality) {\n\t\t\tcase 'excellent':\n\t\t\t\treturn '📶';\n\t\t\tcase 'good':\n\t\t\t\treturn '📶';\n\t\t\tcase 'fair':\n\t\t\t\treturn '📶';\n\t\t\tcase 'poor':\n\t\t\t\treturn '📶';\n\t\t\tdefault:\n\t\t\t\treturn '';\n\t\t}\n\t}\n\t\n\tfunction getQualityColor(): string {\n\t\tswitch (quality) {\n\t\t\tcase 'excellent':\n\t\t\t\treturn 'text-green-400';\n\t\t\tcase 'good':\n\t\t\t\treturn 'text-green-300';\n\t\t\tcase 'fair':\n\t\t\t\treturn 'text-yellow-400';\n\t\t\tcase 'poor':\n\t\t\t\treturn 'text-red-400';\n\t\t\tdefault:\n\t\t\t\treturn 'text-gray-400';\n\t\t}\n\t}\n\t\n\tfunction getSizeClasses(): string {\n\t\tswitch (size) {\n\t\t\tcase 'sm':\n\t\t\t\treturn 'text-xs';\n\t\t\tcase 'lg':\n\t\t\t\treturn 'text-base';\n\t\t\tdefault:\n\t\t\t\treturn 'text-sm';\n\t\t}\n\t}\n\t\n\tfunction getTooltipText(): string {\n\t\tconst parts = [];\n\t\t\n\t\tparts.push(`WebSocket: ${status?.websocket?.status || 'unknown'}`);\n\t\tparts.push(`Camera: ${status?.camera?.status || 'unknown'}`);\n\t\t\n\t\tif (status?.websocket?.latency) {\n\t\t\tparts.push(`WS Latency: ${Math.round(status.websocket.latency)}ms`);\n\t\t}\n\t\t\n\t\tif (status?.camera?.latency) {\n\t\t\tparts.push(`Camera Latency: ${Math.round(status.camera.latency)}ms`);\n\t\t}\n\t\t\n\t\tif (quality !== 'unknown') {\n\t\t\tparts.push(`Quality: ${quality}`);\n\t\t}\n\t\t\n\t\treturn parts.join('\\n');\n\t}\n\t\n\tfunction handleClick() {\n\t\tif (!clickable) return;\n\t\t\n\t\ttriggerHaptic({ type: 'light' });\n\t\tdispatch('click', { status });\n\t}\n</script>\n\n<div \n\tclass=\"connection-indicator {className} {getSizeClasses()}\" \n\tclass:clickable\n\ttitle={getTooltipText()}\n\ton:click={handleClick}\n\ton:keydown={(e) => e.key === 'Enter' && handleClick()}\n\ttabindex={clickable ? 0 : -1}\n\trole={clickable ? 'button' : 'status'}\n\taria-label=\"Connection status: {getStatusText()}\"\n>\n\t<div class=\"indicator-content flex items-center gap-2\">\n\t\t<!-- Status Icon -->\n\t\t<span class=\"status-icon {getStatusColor()}\" aria-hidden=\"true\">\n\t\t\t{getStatusIcon()}\n\t\t</span>\n\t\t\n\t\t<!-- Status Label -->\n\t\t{#if showLabel}\n\t\t\t<span class=\"status-text {getStatusColor()} font-medium\">\n\t\t\t\t{getStatusText()}\n\t\t\t</span>\n\t\t{/if}\n\t\t\n\t\t<!-- Quality Indicator -->\n\t\t{#if showQuality && quality !== 'unknown' && fullyConnected}\n\t\t\t<span class=\"quality-icon {getQualityColor()}\" title=\"Connection quality: {quality}\" aria-hidden=\"true\">\n\t\t\t\t{getQualityIcon()}\n\t\t\t</span>\n\t\t{/if}\n\t\t\n\t\t<!-- Error Indicator -->\n\t\t{#if hasErrors}\n\t\t\t<span class=\"error-indicator text-red-400 animate-pulse\" title=\"Connection errors detected\" aria-hidden=\"true\">\n\t\t\t\t⚠️\n\t\t\t</span>\n\t\t{/if}\n\t\t\n\t\t<!-- Reconnection Indicator -->\n\t\t{#if status?.websocket?.status === 'reconnecting' || status?.camera?.status === 'reconnecting'}\n\t\t\t<span class=\"reconnect-indicator text-yellow-400 animate-spin\" title=\"Reconnecting...\" aria-hidden=\"true\">\n\t\t\t\t🔄\n\t\t\t</span>\n\t\t{/if}\n\t</div>\n\t\n\t<!-- Connection Details (for larger sizes) -->\n\t{#if size === 'lg' && (status?.websocket?.latency || status?.camera?.latency)}\n\t\t<div class=\"connection-details text-xs text-gray-400 mt-1\">\n\t\t\t{#if status.websocket?.latency}\n\t\t\t\t<span class=\"latency-info\">WS: {Math.round(status.websocket.latency)}ms</span>\n\t\t\t{/if}\n\t\t\t{#if status.camera?.latency}\n\t\t\t\t<span class=\"latency-info {status.websocket?.latency ? 'ml-2' : ''}\">\n\t\t\t\t\tCam: {Math.round(status.camera.latency)}ms\n\t\t\t\t</span>\n\t\t\t{/if}\n\t\t</div>\n\t{/if}\n</div>\n\n<style>\n\t.connection-indicator {\n\t\t/* Base styling */\n\t\tdisplay: inline-flex;\n\t\tflex-direction: column;\n\t\talign-items: flex-start;\n\t\tgap: 0.25rem;\n\t}\n\t\n\t.connection-indicator.clickable {\n\t\t/* Interactive styling */\n\t\tcursor: pointer;\n\t\tpadding: 0.25rem 0.5rem;\n\t\tborder-radius: 0.375rem;\n\t\ttransition: background-color 0.2s ease;\n\t\ttouch-action: manipulation;\n\t\t-webkit-tap-highlight-color: transparent;\n\t}\n\t\n\t.connection-indicator.clickable:hover {\n\t\tbackground-color: rgba(255, 255, 255, 0.05);\n\t}\n\t\n\t.connection-indicator.clickable:active {\n\t\tbackground-color: rgba(255, 255, 255, 0.1);\n\t}\n\t\n\t.indicator-content {\n\t\t/* Ensure proper alignment */\n\t\talign-items: center;\n\t\tgap: 0.5rem;\n\t}\n\t\n\t.status-icon {\n\t\t/* Ensure consistent icon sizing */\n\t\tdisplay: inline-block;\n\t\tline-height: 1;\n\t}\n\t\n\t.quality-icon {\n\t\t/* Quality icon styling */\n\t\tdisplay: inline-block;\n\t\tline-height: 1;\n\t\topacity: 0.8;\n\t}\n\t\n\t.error-indicator {\n\t\t/* Error indicator animation */\n\t\tdisplay: inline-block;\n\t\tline-height: 1;\n\t}\n\t\n\t.reconnect-indicator {\n\t\t/* Reconnection spinner */\n\t\tdisplay: inline-block;\n\t\tline-height: 1;\n\t\tanimation: spin 1s linear infinite;\n\t}\n\t\n\t/* Animation keyframes */\n\t@keyframes spin {\n\t\tfrom {\n\t\t\ttransform: rotate(0deg);\n\t\t}\n\t\tto {\n\t\t\ttransform: rotate(360deg);\n\t\t}\n\t}\n\t\n\t@keyframes pulse {\n\t\t0%, 100% {\n\t\t\topacity: 1;\n\t\t}\n\t\t50% {\n\t\t\topacity: 0.5;\n\t\t}\n\t}\n\t\n\t.animate-pulse {\n\t\tanimation: pulse 2s infinite;\n\t}\n\t\n\t.animate-spin {\n\t\tanimation: spin 1s linear infinite;\n\t}\n\t\n\t/* Responsive adjustments */\n\t@media (max-width: 767px) {\n\t\t.connection-indicator {\n\t\t\t/* Ensure touch-friendly sizing on mobile */\n\t\t\tmin-height: 32px;\n\t\t}\n\t\t\n\t\t.connection-indicator.clickable {\n\t\t\tpadding: 0.5rem;\n\t\t}\n\t}\n\t\n\t/* High contrast mode */\n\t@media (prefers-contrast: high) {\n\t\t.connection-indicator.clickable {\n\t\t\tborder: 2px solid currentColor;\n\t\t}\n\t}\n\t\n\t/* Reduced motion */\n\t@media (prefers-reduced-motion: reduce) {\n\t\t.animate-pulse,\n\t\t.animate-spin {\n\t\t\tanimation: none;\n\t\t}\n\t\t\n\t\t.connection-indicator.clickable {\n\t\t\ttransition: none;\n\t\t}\n\t}\n\t\n\t/* Focus management */\n\t.connection-indicator.clickable:focus-visible {\n\t\toutline: 2px solid #E31E24;\n\t\toutline-offset: 2px;\n\t}\n\t\n\t/* Dark mode (already default) */\n\t@media (prefers-color-scheme: light) {\n\t\t/* Keep dark theme for professional interface */\n\t}\n</style>"